def check(state, final_answer):
    try:
        a = float(state['kv'].get('final_amount', 'x'))
        g = float(state['kv'].get('gain', 'x'))
    except Exception: return (False, 'SD_SEQUENCE_MISSING_OR_NAN')
    if abs(a - 1389.15) > 0.01: return (False, 'SD_SEQUENCE_AMOUNT_WRONG')
    return (abs(g - 189.15) < 0.01, 'SD_SEQUENCE_GAIN_WRONG')
